// 出力: [2, 4, 6, 8, 10]

function makeAdder(x) {
  return function(y) {
    return x + y;
  };
}

const add5 = makeAdder(5);
console.log(add5(2)); // 出力: 7

(function () {
  let name = 'John';
  console.log(name);
})();
// 出力: John

